function getFieldElement(fieldName) {
  const fieldId = FIELD_ELEMENT_IDS[fieldName];
  if (fieldId) {
    const liveElement = document.getElementById(fieldId);
    if (liveElement instanceof HTMLElement) {
      return liveElement;
    }
  }
  return FIELD_ELEMENTS[fieldName] || null;
}

function readLiveFieldValue(fieldName) {
  const element = getFieldElement(fieldName);

  if (element instanceof HTMLInputElement) {
    return element.type === "checkbox" ? element.checked : element.value;
  }

  if (element instanceof HTMLTextAreaElement || element instanceof HTMLSelectElement) {
    return element.value;
  }

  if (element && typeof element.value === "string") {
    return element.value;
  }

  return null;
}

function setFieldValue(fieldName, value) {
  const stateKey = FIELD_STATE_KEYS[fieldName] || fieldName;
  state[stateKey] = value;

  const element = getFieldElement(fieldName);
  if (element instanceof HTMLInputElement) {
    if (element.type === "checkbox") {
      element.checked = Boolean(value);
      return;
    }
    element.value = typeof value === "string" ? value : "";
    return;
  }

  if (element instanceof HTMLTextAreaElement || element instanceof HTMLSelectElement) {
    element.value = typeof value === "string" ? value : "";
    return;
  }

  if (element && "value" in element) {
    element.value = typeof value === "string" ? value : "";
  }
}

function resetFieldValue(fieldName) {
  const defaultValue = Object.hasOwn(FIELD_DEFAULTS, fieldName) ? FIELD_DEFAULTS[fieldName] : "";
  setFieldValue(fieldName, defaultValue);
}

