function initializeSectionShells() {
  for (const config of Object.values(SECTION_CONFIG)) {
    if (!config?.element || config.body) {
      continue;
    }

    const body = document.createElement("div");
    body.className = "report-section-body";
    body.id = `${config.targetId}-body`;

    while (config.element.firstChild) {
      body.appendChild(config.element.firstChild);
    }

    const summaryButton = document.createElement("button");
    summaryButton.type = "button";
    summaryButton.className = "report-section-summary";
    summaryButton.hidden = true;
    summaryButton.setAttribute("aria-controls", body.id);
    summaryButton.innerHTML = `
      <span class="report-section-summary__status">Completed</span>
      <span class="report-section-summary__label">${config.label}</span>
      <span class="report-section-summary__value"></span>
      <span class="report-section-summary__action">Edit</span>
    `;

    config.element.append(summaryButton, body);
    config.body = body;
    config.summaryButton = summaryButton;
    config.summaryValue = summaryButton.querySelector(".report-section-summary__value");
  }
}

initializeSectionShells();

