  "progress-intent": "Make a selection to continue.",
  "progress-topic": "Make a selection to continue.",
  "progress-failed-bank-branch": "Choose the failed-bank request that best matches your need.",
  "progress-failed-bank-identification": "Enter the failed bank name or certificate number to continue.",
  "progress-specific-bank": "Select a bank if one institution is involved, or continue to skip this optional step.",
  "progress-appraisal-details": "Provide your role and the property details.",
  "progress-document-request-type": "Select the type of record or document you need.",
  "progress-narrative": "Enter details to continue.",
  "progress-outcome": "Make a selection to continue.",
  "progress-identity": "Complete the required contact fields to continue.",
