const FAILED_BANK_DATA_URL = "https://www.fdic.gov/bank-failures/download-data.csv";
const FAILED_BANK_SUGGESTION_LIMIT = 8;
const FAILED_BANK_LOOKBACK_YEARS = 5;

let endpointProfiles = {};
let contextualFaqController = null;
let activeStepKey = "";
let pendingLiveStatusMessage = "";
let lastLiveStatusMessage = "";
let faqGateArmed = false;
let autoSaveTimer = null;
let failedBankDirectory = [];
let failedBankDirectoryState = "idle";
let comboboxOpen = false;
let comboboxActiveIndex = -1;
let comboboxBrowseMode = false;

function getCurrentWorkflow() {
  return state.intent ? WORKFLOWS[state.intent] || null : null;
}

function getSelectedTopic() {
  const workflow = getCurrentWorkflow();
  return workflow?.topics.find((topic) => topic.value === state.topic) || null;
}

function getBranchConfig() {
  return FAILED_BANK_BRANCH_CONFIG[state.topic] || null;
}

function getSpecificBankConfig() {
  return SPECIFIC_BANK_TOPIC_CONFIG[state.topic] || null;
}

function getRegulatorHandoffProfile() {
  return getRegulatorHandoffProfileForBank(state.specificBankDetails, Boolean(getSpecificBankConfig()));
}

function getBranchOption() {
  const config = getBranchConfig();
  return config?.options.find((option) => option.value === state.sub) || null;
}

function getBranchLabel() {
  return getBranchOption()?.title || "";
}

function getTopicDisplayTitle() {
  const selectedTopic = getSelectedTopic();
  if (!selectedTopic) {
    return "";
  }

  const branchLabel = getBranchLabel();
  const documentRequestType = state.documentRequestType.trim();
  const detailSuffix = branchLabel || documentRequestType;
  return detailSuffix ? `${selectedTopic.title}: ${detailSuffix}` : selectedTopic.title;
}

function branchSelectionIsRequired() {
  return Boolean(getBranchConfig());
}

function isBranchSelectionComplete() {
  return !branchSelectionIsRequired() || Boolean(state.sub);
}

function getActiveProfile() {
  const selectedTopic = getSelectedTopic();
  if (!selectedTopic) {
    return null;
  }
  return endpointProfiles[selectedTopic.endpointKey] || null;
}

async function fetchProfiles() {
  const response = await fetch(ENDPOINT_PROFILES_PATH, { cache: "no-store" });
  if (!response.ok) {
    throw new Error(`Unable to load endpoint profiles (${response.status}).`);
  }
  endpointProfiles = await response.json();
  return endpointProfiles;
}

function getFieldValue(fieldName) {
  const liveValue = readLiveFieldValue(fieldName);
  if (typeof liveValue === "boolean") {
    return liveValue;
  }
  if (typeof liveValue === "string") {
    return liveValue.trim();
  }

  const stateKey = FIELD_STATE_KEYS[fieldName] || fieldName;
  const value = state[stateKey];
  return typeof value === "string" ? value.trim() : value;
}

function hasMappedField(fieldName) {
  return Boolean(getFieldElement(fieldName));
}

function getProfileRequiredFields(profile) {
  const fields = Array.isArray(profile?.requiredFields) ? [...profile.requiredFields] : [];
  const selectedTopic = getSelectedTopic();

  if (selectedTopic?.includeDesiredResolution && !fields.includes("desiredResolution")) {
    fields.push("desiredResolution");
  }

  return fields;
}

function getProfileSections(profile) {
  const sections = Array.isArray(profile?.sections) ? [...profile.sections] : [];
  const selectedTopic = getSelectedTopic();

  const insertAfter = (sectionName, afterSectionName) => {
    if (sections.includes(sectionName)) {
      return;
    }
    const afterIndex = sections.indexOf(afterSectionName);
    const fallbackIndex = sections.indexOf("narrative");
    const insertIndex = afterIndex >= 0
      ? afterIndex + 1
      : fallbackIndex >= 0
        ? fallbackIndex + 1
        : sections.length;
    sections.splice(insertIndex, 0, sectionName);
  };

  if (selectedTopic?.includeOutcome && !sections.includes("outcome")) {
    insertAfter("outcome", "narrative");
  }

  if (selectedTopic?.includeDesiredResolution) {
    insertAfter("desiredResolution", "mailingAddress");
  }

  return sections;
}

function profileIncludesSection(profile, sectionName) {
  return getProfileSections(profile).includes(sectionName);
}

function fieldIsRequired(profile, fieldName) {
  return getProfileRequiredFields(profile).includes(fieldName);
}

function sectionHasRequiredFields(profile, sectionName) {
  const fields = SECTION_FIELDS[sectionName] || [];
  return fields.some((fieldName) => fieldIsRequired(profile, fieldName));
}

function setFieldRequired(fieldName, required) {
  const field = getFieldElement(fieldName);
  const marker = FIELD_REQUIRED_MARKERS[fieldName];

  if (field instanceof HTMLElement) {
    field.toggleAttribute("required", required);
    field.setAttribute("aria-required", required ? "true" : "false");
  }

  if (marker instanceof HTMLElement) {
    marker.hidden = !required;
  }
}

function applyProfileRequirements(profile) {
  for (const fieldName of Object.keys(FIELD_ELEMENTS)) {
    setFieldRequired(fieldName, fieldIsRequired(profile, fieldName));
  }

  for (const [sectionName, marker] of Object.entries(SECTION_REQUIRED_MARKERS)) {
    if (!(marker instanceof HTMLElement)) {
      continue;
    }
    marker.hidden = !sectionHasRequiredFields(profile, sectionName);
  }
}

function isFieldComplete(profile, fieldName) {
  if (!fieldIsRequired(profile, fieldName)) {
    return true;
  }
  if (!hasMappedField(fieldName)) {
    return true;
  }

  const value = getFieldValue(fieldName);

  if (fieldName === "email") {
    return Boolean(value && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value));
  }

  if (fieldName === "emailConfirm") {
    return Boolean(value && value.toLowerCase() === getFieldValue("email").toLowerCase());
  }

  if (fieldName === "businessPhone") {
    return Boolean(value && /^[0-9+()\-\s.]{7,}$/.test(value));
  }

  if (fieldName === "authorization") {
    return Boolean(getFieldValue(fieldName));
  }

  return Boolean(value);
}

function isProfileComplete(profile, currentState) {
  if (!profile || profile.pattern !== "intake") {
    return false;
  }

  return getProfileRequiredFields(profile).every((fieldName) => {
    const stateKey = FIELD_STATE_KEYS[fieldName] || fieldName;
    if (!(stateKey in currentState) && !hasMappedField(fieldName)) {
      return true;
    }
    return isFieldComplete(profile, fieldName);
  });
}

function isIntakeComplete(profile) {
  return Boolean(
    state.intent &&
      state.topic &&
      isBranchSelectionComplete() &&
      (!profileIncludesSection(profile, "outcome") || state.outcome) &&
      isProfileComplete(profile, state)
  );
}

function populateStateOptions() {
  const input = getFieldElement("mailingState");
  if (!(input instanceof HTMLSelectElement) || input.options.length > 1) {
    return;
  }
  const options = US_STATES_AND_TERRITORIES.map((name) => `<option value="${name}">${name}</option>`).join("");
  input.insertAdjacentHTML("beforeend", options);
}

function populateDocumentRequestTypeOptions() {
  const input = getFieldElement("documentRequestType");
  if (!(input instanceof HTMLSelectElement) || input.options.length > 1) {
    return;
  }

  const options = DOCUMENT_REQUEST_TYPE_OPTIONS
    .map((option) => `<option value="${escapeHtml(option.value)}">${escapeHtml(option.label)}</option>`)
    .join("");
  input.insertAdjacentHTML("beforeend", options);
}

function populateAppraisalRoleOptions() {
  const input = getFieldElement("appraisalRole");
  if (!(input instanceof HTMLSelectElement) || input.options.length > 1) {
    return;
  }

  const options = APPRAISAL_ROLE_OPTIONS
    .map((option) => `<option value="${escapeHtml(option.value)}">${escapeHtml(option.label)}</option>`)
    .join("");
  input.insertAdjacentHTML("beforeend", options);
}

function populateDeferredSelectOptions() {
  populateStateOptions();
  populateDocumentRequestTypeOptions();
  populateAppraisalRoleOptions();

  window.requestAnimationFrame(() => {
    populateStateOptions();
    populateDocumentRequestTypeOptions();
    populateAppraisalRoleOptions();
  });
}

function getContextualFaqTerms({ includeUserInput = false } = {}) {
  const workflow = getCurrentWorkflow();
  const selectedTopic = getSelectedTopic();
  const sources = [
    state.intent,
    state.topic,
    getBranchLabel(),
    state.documentRequestType,
    selectedTopic?.title || "",
    selectedTopic?.detail || "",
    workflow?.heading || "",
  ];
  if (includeUserInput && detailsInput) {
    sources.push(detailsInput.value || "");
  }
  return sources
    .join(" ")
    .toLowerCase()
    .split(/[^a-z0-9]+/)
    .filter(Boolean);
}

function getContextualFaqSuggestions(articles, terms, limit = 3) {
  if (!terms.length) {
    return [];
  }
  const ranked = articles
    .map((article) => {
      const question = (article.question || "").toLowerCase();
      const summary = (article.summary || "").toLowerCase();
      const topicText = Array.isArray(article.topics)
        ? article.topics.map((topic) => (topic?.label || "").toLowerCase()).join(" ")
        : "";
      let score = 0;
      for (const term of terms) {
        if (question.includes(term)) score += 6;
        if (topicText.includes(term)) score += 4;
        if (summary.includes(term)) score += 1;
      }
      return { article, score };
    })
    .filter((entry) => entry.score > 0)
    .sort((a, b) => b.score - a.score);

  const picked = [];
  const seen = new Set();
  for (const entry of ranked) {
    const key = entry.article?.urlName || entry.article?.id;
    if (!key || seen.has(key)) continue;
    picked.push(entry.article);
    seen.add(key);
    if (picked.length >= limit) break;
  }
  return picked;
}

function renderContextualFaqFallback() {
  if (!contextualFaqWrapper || !contextualFaqList) {
    return;
  }
  contextualFaqList.replaceChildren();
  contextualFaqWrapper.hidden = true;
}

let contextualFaqDismissed = false;
let contextualFaqDataPromise = null;

function loadContextualFaqData(signal) {
  if (!contextualFaqDataPromise) {
    // Try the slim build-time index first; fall back to the full corpus if
    // the index is missing (e.g. a stale build). The matcher only reads
    // question/topic/urlName, all of which are present in both shapes.
    contextualFaqDataPromise = fetch(FAQ_INDEX_PATH, { cache: "force-cache" })
      .then((response) => {
        if (response.ok) return response.json();
        return fetch(FAQ_DATA_PATH, { cache: "force-cache" }).then((r) => {
          if (!r.ok) throw new Error("Unable to load FAQs.");
          return r.json();
        });
      })
      .catch((error) => {
        contextualFaqDataPromise = null;
        throw error;
      });
  }
  if (signal) {
    return new Promise((resolve, reject) => {
      if (signal.aborted) {
        reject(new DOMException("Aborted", "AbortError"));
        return;
      }
      signal.addEventListener("abort", () => {
        reject(new DOMException("Aborted", "AbortError"));
      }, { once: true });
      contextualFaqDataPromise.then(resolve, reject);
    });
  }
  return contextualFaqDataPromise;
}

const contextualFaqDismissButton = document.getElementById("contextual-faq-dismiss");
if (contextualFaqDismissButton) {
  contextualFaqDismissButton.addEventListener("click", () => {
    contextualFaqDismissed = true;
    if (contextualFaqWrapper) {
      contextualFaqWrapper.hidden = true;
    }
  });
}

function buildFaqListItems(suggestions) {
  const fragment = document.createDocumentFragment();
  for (const article of suggestions) {
    const hash = `faq-${article.urlName || article.id}`;
    const li = document.createElement("li");
    const a = document.createElement("a");
    a.href = `faq.html#${hash}`;
    a.textContent = stripQuestionPrefix(article.question || "Untitled FAQ");
    li.appendChild(a);
    fragment.appendChild(li);
  }
  return fragment;
}

function renderContextualFaqSuggestions({ fromBlur = false } = {}) {
  if (!contextualFaqWrapper || !contextualFaqList) {
    return;
  }

  // When not triggered by blur, just hide — FAQs only appear after textarea blur
  if (!fromBlur) {
    if (contextualFaqController) {
      contextualFaqController.abort();
      contextualFaqController = null;
    }
    contextualFaqWrapper.hidden = true;
    return;
  }

  if (!state.topic || contextualFaqDismissed) {
    renderContextualFaqFallback();
    return;
  }

  const userText = (detailsInput?.value || "").trim();
  if (userText.length < 20) {
    renderContextualFaqFallback();
    return;
  }

  if (contextualFaqController) {
    contextualFaqController.abort();
  }
  contextualFaqController = new AbortController();

  loadContextualFaqData(contextualFaqController.signal)
    .then((data) => {
      const articles = Array.isArray(data?.articles) ? data.articles : [];
      const terms = getContextualFaqTerms({ includeUserInput: true });
      const suggestions = getContextualFaqSuggestions(articles, terms, 3);
      if (suggestions.length < 2) {
        renderContextualFaqFallback();
        return;
      }
      contextualFaqList.replaceChildren(buildFaqListItems(suggestions));

      const faqWasHidden = contextualFaqWrapper.hidden;
      contextualFaqWrapper.hidden = false;
      if (faqWasHidden) {
        triggerRevealAnimation(contextualFaqWrapper, "is-revealing");
      }
    })
    .catch((error) => {
      if (error?.name === "AbortError") return;
      renderContextualFaqFallback();
    });
}

// Show refined FAQs when user tabs out of the details textarea
if (detailsInput) {
  // Warm the FAQ corpus on first focus so suggestions feel instant on blur,
  // without paying the 449 KB cost on every intake page view.
  detailsInput.addEventListener("focus", () => {
    if (contextualFaqDismissed) return;
    loadContextualFaqData().catch(() => { /* swallow — render path will retry */ });
  }, { once: true });
  detailsInput.addEventListener("blur", () => {
    if (contextualFaqDismissed) return;
    renderContextualFaqSuggestions({ fromBlur: true });
  });
}

